import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { toast } from "react-toastify";

function Home() {
  const user = useSelector((state) => state.auth.user);
  const [announcements, setAnnouncements] = useState([]);
  const [notifications, setNotifications] = useState([]);

  useEffect(() => {
    // Загрузка объявлений
    fetch("http://localhost:3001/announcements")
      .then((res) => res.json())
      .then((data) => setAnnouncements(data))
      .catch((error) => toast.error("Ошибка загрузки объявлений"));

    // Загрузка уведомлений для авторизованного пользователя
    if (user?.id) {
      fetch(`http://localhost:3001/notifications?userId=${user.id}`)
        .then((res) => res.json())
        .then((data) => setNotifications(data))
        .catch((error) => toast.error("Ошибка загрузки уведомлений"));
    }
  }, [user]);

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Добро пожаловать в систему обучения!</h1>

      {/* Приветственное сообщение */}
      <div className="card shadow mb-4">
        <div className="card-body">
          {user ? (
            <>
              <h2>Здравствуйте, {user.name}!</h2>
              <p>
                Вы вошли как <strong>{user.role}</strong>. Используйте меню ниже
                для доступа к вашим функциям.
              </p>
              <div className="d-flex gap-2">
                <Link to="/dashboard" className="btn btn-primary">
                  Личный кабинет
                </Link>
                <Link to="/courses" className="btn btn-primary">
                  {user.role === "teacher" ? "Мои курсы" : "Доступные курсы"}
                </Link>
                {user.role === "admin" && (
                  <Link to="/admin" className="btn btn-primary">
                    Панель администратора
                  </Link>
                )}
                {user.role === "student" && (
                  <Link to="/enrollments" className="btn btn-primary">
                    Мои записи
                  </Link>
                )}
              </div>
            </>
          ) : (
            <>
              <h2>Присоединяйтесь к нашей платформе!</h2>
              <p>
                Войдите или зарегистрируйтесь, чтобы получить доступ к курсам,
                материалам и персонализированным функциям.
              </p>
              <div className="d-flex gap-2">
                <Link to="/login" className="btn btn-primary">
                  Войти
                </Link>
                <Link to="/register" className="btn btn-secondary">
                  Зарегистрироваться
                </Link>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Последние объявления */}
      <div className="card shadow mb-4">
        <div className="card-body">
          <h2 className="mb-3">Последние объявления</h2>
          {announcements.length === 0 ? (
            <p>Объявлений нет</p>
          ) : (
            <ul className="list-group">
              {announcements.slice(0, 3).map((announcement) => (
                <li key={announcement.id} className="list-group-item">
                  <strong>{announcement.title}</strong>
                  <p>{announcement.message}</p>
                  <small>
                    {new Date(announcement.createdAt).toLocaleString()}
                  </small>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>

      {/* Уведомления для авторизованного пользователя */}
      {user && (
        <div className="card shadow mb-4">
          <div className="card-body">
            <h2 className="mb-3">Ваши уведомления</h2>
            {notifications.length === 0 ? (
              <p>Уведомлений нет</p>
            ) : (
              <ul className="list-group">
                {notifications.slice(0, 3).map((notification) => (
                  <li key={notification.id} className="list-group-item">
                    {notification.message}
                    <br />
                    <small>
                      {new Date(notification.createdAt).toLocaleString()}
                    </small>
                  </li>
                ))}
              </ul>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default Home;
